# Bad: one handler for everything
try:
    process_order(order)
except Exception as exc:
    log.error("Failed: %s", exc)
    mark_failed(order.id)

# Good: separate business vs application exceptions
try:
    validate(order)       # raises BusinessException on invalid data
    update_erp(order)     # raises ApplicationException on UI failure
except BusinessException as exc:
    route_to_human_queue(order, reason=str(exc))
except ApplicationException as exc:
    if retry_count < MAX_RETRIES:
        retry_with_backoff(order)
    else:
        alert_operations(order, str(exc))

# Bad: no idempotency check
def submit_order(order):
    open_app()
    fill_form(order)
    click_submit()  # crash here → duplicate on restart

# Good: check for existing record before submitting
def submit_order(order):
    if erp_record_exists(order.id):
        log.info("Order %s already in ERP — skipping submit", order.id)
        return get_existing_confirmation(order.id)
    open_app()
    fill_form(order)
    click_submit()
